import MentionResolver from '../src/mentions/MentionResolver.js';
import FileSystemManager from '../src/filesystem/FileSystemManager.js';
import fs from 'fs/promises';
import path from 'path';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

describe('MentionResolver', () => {
  let resolver;
  let fsManager;
  let testDir;

  beforeEach(async () => {
    // Create a temporary test directory
    testDir = path.join(__dirname, 'test-mentions-temp');
    await fs.mkdir(testDir, { recursive: true });

    // Create test file structure
    await fs.mkdir(path.join(testDir, 'src'), { recursive: true });
    await fs.mkdir(path.join(testDir, 'src', 'components'), { recursive: true });
    await fs.mkdir(path.join(testDir, 'tests'), { recursive: true });
    
    await fs.writeFile(path.join(testDir, 'index.js'), 'console.log("index");');
    await fs.writeFile(path.join(testDir, 'README.md'), '# Test Project');
    await fs.writeFile(path.join(testDir, 'src', 'app.js'), 'console.log("app");');
    await fs.writeFile(path.join(testDir, 'src', 'utils.js'), 'export const util = () => {};');
    await fs.writeFile(path.join(testDir, 'src', 'components', 'Button.js'), 'export const Button = () => {};');
    await fs.writeFile(path.join(testDir, 'tests', 'app.test.js'), 'test("app", () => {});');
    
    // Create a large file for size testing
    const largeContent = 'x'.repeat(600 * 1024); // 600KB
    await fs.writeFile(path.join(testDir, 'large.txt'), largeContent);
    
    // Create a very large file
    const veryLargeContent = 'x'.repeat(2 * 1024 * 1024); // 2MB
    await fs.writeFile(path.join(testDir, 'verylarge.txt'), veryLargeContent);

    fsManager = new FileSystemManager(testDir);
    resolver = new MentionResolver(fsManager, {
      maxFileSize: 1024 * 1024, // 1MB
      warnFileSize: 512 * 1024  // 512KB
    });
  });

  afterEach(async () => {
    // Clean up test directory
    await fs.rm(testDir, { recursive: true, force: true });
  });

  describe('resolve', () => {
    it('should resolve a single existing file', async () => {
      const results = await resolver.resolve(['index.js']);
      
      expect(results).toHaveLength(1);
      expect(results[0].mention).toBe('index.js');
      expect(results[0].resolvedPaths).toEqual(['index.js']);
      expect(results[0].isGlob).toBe(false);
      expect(results[0].error).toBeUndefined();
    });

    it('should resolve multiple files', async () => {
      const results = await resolver.resolve(['index.js', 'README.md']);
      
      expect(results).toHaveLength(2);
      expect(results[0].resolvedPaths).toEqual(['index.js']);
      expect(results[1].resolvedPaths).toEqual(['README.md']);
    });

    it('should handle non-existent files with suggestions', async () => {
      const results = await resolver.resolve(['nonexistent.js']);
      
      expect(results).toHaveLength(1);
      expect(results[0].resolvedPaths).toEqual([]);
      expect(results[0].error).toContain('File not found');
      expect(results[0].suggestions).toBeDefined();
    });

    it('should resolve glob patterns', async () => {
      const results = await resolver.resolve(['src/**/*.js']);
      
      expect(results).toHaveLength(1);
      expect(results[0].isGlob).toBe(true);
      expect(results[0].resolvedPaths.length).toBeGreaterThan(0);
      expect(results[0].resolvedPaths).toContain('src/app.js');
      expect(results[0].resolvedPaths).toContain('src/utils.js');
    });

    it('should resolve wildcard patterns', async () => {
      const results = await resolver.resolve(['*.md']);
      
      expect(results).toHaveLength(1);
      expect(results[0].isGlob).toBe(true);
      expect(results[0].resolvedPaths).toContain('README.md');
    });

    it('should handle nested file paths', async () => {
      const results = await resolver.resolve(['src/components/Button.js']);
      
      expect(results).toHaveLength(1);
      expect(results[0].resolvedPaths).toEqual(['src/components/Button.js']);
    });
  });

  describe('readMentionedFiles', () => {
    it('should read file contents', async () => {
      const results = await resolver.readMentionedFiles(['index.js']);
      
      expect(results).toHaveLength(1);
      expect(results[0].path).toBe('index.js');
      expect(results[0].content).toBe('console.log("index");');
      expect(results[0].size).toBeGreaterThan(0);
      expect(results[0].error).toBeUndefined();
    });

    it('should read multiple files', async () => {
      const results = await resolver.readMentionedFiles(['index.js', 'README.md']);
      
      expect(results).toHaveLength(2);
      expect(results[0].content).toBe('console.log("index");');
      expect(results[1].content).toBe('# Test Project');
    });

    it('should handle non-existent files', async () => {
      const results = await resolver.readMentionedFiles(['nonexistent.js']);
      
      expect(results).toHaveLength(1);
      expect(results[0].content).toBeNull();
      expect(results[0].error).toContain('File not found');
    });

    it('should warn about large files', async () => {
      const results = await resolver.readMentionedFiles(['large.txt']);
      
      expect(results).toHaveLength(1);
      expect(results[0].content).toBeDefined();
      expect(results[0].warning).toContain('large');
    });

    it('should reject files exceeding max size', async () => {
      const results = await resolver.readMentionedFiles(['verylarge.txt']);
      
      expect(results).toHaveLength(1);
      expect(results[0].content).toBeNull();
      expect(results[0].error).toContain('too large');
    });

    it('should handle nested file paths', async () => {
      const results = await resolver.readMentionedFiles(['src/components/Button.js']);
      
      expect(results).toHaveLength(1);
      expect(results[0].content).toBe('export const Button = () => {};');
    });
  });

  describe('validateFileSize', () => {
    it('should allow small files', async () => {
      const result = await resolver.validateFileSize('index.js');
      
      expect(result.allowed).toBe(true);
      expect(result.size).toBeGreaterThan(0);
      expect(result.warning).toBeUndefined();
      expect(result.error).toBeUndefined();
    });

    it('should warn about large files', async () => {
      const result = await resolver.validateFileSize('large.txt');
      
      expect(result.allowed).toBe(true);
      expect(result.size).toBeGreaterThan(512 * 1024);
      expect(result.warning).toContain('large');
    });

    it('should reject files exceeding max size', async () => {
      const result = await resolver.validateFileSize('verylarge.txt');
      
      expect(result.allowed).toBe(false);
      expect(result.size).toBeGreaterThan(1024 * 1024);
      expect(result.error).toContain('too large');
    });

    it('should handle non-existent files', async () => {
      const result = await resolver.validateFileSize('nonexistent.js');
      
      expect(result.allowed).toBe(false);
      expect(result.error).toContain('File not found');
    });
  });

  describe('getAutocomplete', () => {
    it('should provide autocomplete suggestions for partial filename', async () => {
      const results = await resolver.getAutocomplete('ind');
      
      expect(results.length).toBeGreaterThan(0);
      expect(results[0].path).toBe('index.js');
      expect(results[0].score).toBeGreaterThan(0);
    });

    it('should provide suggestions for partial path', async () => {
      const results = await resolver.getAutocomplete('src/app');
      
      expect(results.length).toBeGreaterThan(0);
      const appFile = results.find(r => r.path === 'src/app.js');
      expect(appFile).toBeDefined();
    });

    it('should rank exact matches higher', async () => {
      const results = await resolver.getAutocomplete('index.js');
      
      expect(results.length).toBeGreaterThan(0);
      expect(results[0].path).toBe('index.js');
      expect(results[0].score).toBeGreaterThan(900);
    });

    it('should rank prefix matches high', async () => {
      const results = await resolver.getAutocomplete('README');
      
      expect(results.length).toBeGreaterThan(0);
      expect(results[0].path).toBe('README.md');
      expect(results[0].score).toBeGreaterThan(800);
    });

    it('should support fuzzy matching', async () => {
      const results = await resolver.getAutocomplete('btn');
      
      const buttonFile = results.find(r => r.path.includes('Button.js'));
      expect(buttonFile).toBeDefined();
      expect(buttonFile.score).toBeGreaterThan(0);
    });

    it('should limit results to maxResults', async () => {
      const results = await resolver.getAutocomplete('', { maxResults: 3 });
      
      expect(results.length).toBeLessThanOrEqual(3);
    });

    it('should handle empty partial string', async () => {
      const results = await resolver.getAutocomplete('');
      
      expect(results).toEqual([]);
    });

    it('should return empty array for no matches', async () => {
      const results = await resolver.getAutocomplete('zzzzzzzzz');
      
      expect(results).toEqual([]);
    });

    it('should sort by score and path length', async () => {
      const results = await resolver.getAutocomplete('js');
      
      // Results should be sorted by score (descending)
      for (let i = 1; i < results.length; i++) {
        expect(results[i - 1].score).toBeGreaterThanOrEqual(results[i].score);
      }
    });
  });

  describe('_fuzzyMatch', () => {
    it('should score exact matches highest', () => {
      const score = resolver._fuzzyMatch('test', 'test');
      expect(score).toBe(1000);
    });

    it('should score prefix matches high', () => {
      const score = resolver._fuzzyMatch('test', 'testing');
      expect(score).toBe(900);
    });

    it('should score contains matches medium', () => {
      const score = resolver._fuzzyMatch('test', 'my-test-file');
      expect(score).toBe(800);
    });

    it('should score fuzzy matches lower', () => {
      const score = resolver._fuzzyMatch('btn', 'Button.js');
      expect(score).toBeGreaterThan(0);
      expect(score).toBeLessThan(800);
    });

    it('should return 0 for no match', () => {
      const score = resolver._fuzzyMatch('xyz', 'abc');
      expect(score).toBe(0);
    });

    it('should be case insensitive', () => {
      const score1 = resolver._fuzzyMatch('TEST', 'test');
      const score2 = resolver._fuzzyMatch('test', 'TEST');
      expect(score1).toBe(1000);
      expect(score2).toBe(1000);
    });

    it('should handle empty strings', () => {
      const score = resolver._fuzzyMatch('', 'test');
      expect(score).toBe(0);
    });
  });
});
